import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse(`{"title":"Alias Git : simplifiez votre workflow de versioning | Dotfiles (FR)","titleTemplate":":title","description":"Plus de 80 alias Git pour des commits, branches, diffs et remotes plus rapides. Accélérez vos tâches quotidiennes.","frontmatter":{"title":"Alias Git : simplifiez votre workflow de versioning","description":"Plus de 80 alias Git pour des commits, branches, diffs et remotes plus rapides. Accélérez vos tâches quotidiennes.","lang":"fr-FR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Git : simplifiez votre workflow de versioning preview","canonical":"/fr/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Git : simplifiez votre workflow de versioning","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Git | Dotfiles","permalink":"/fr/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"alias git, raccourcis git, git dotfiles, alias git commit, alias git branch, alias git push, shell, bash, zsh, linux, macos"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Plus de 80 alias Git pour des commits, branches, diffs et remotes plus rapides. Accélérez vos tâches quotidiennes."},{"name":"twitter:title","content":"Alias Git | Dotfiles"},{"name":"og:title","content":"Alias Git | Dotfiles"},{"name":"og:description","content":"Plus de 80 alias Git pour des commits, branches, diffs et remotes plus rapides. Accélérez vos tâches quotidiennes."},{"name":"og:image:alt","content":"Dotfiles - Conçus pour s'adapter à votre vie de shell"},{"name":"og:locale","content":"fr_FR"}]},"headers":[],"relativePath":"fr/aliases/git/index.md","filePath":"fr/aliases/git/index.md","lastUpdated":1773010926000}`),c={name:"fr/aliases/git/index.md"};function i(a,t,s,n,l,g){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="alias-git" tabindex="-1">Alias Git <a class="header-anchor" href="#alias-git" aria-label="Permalink to &quot;Alias Git&quot;">​</a></h1><p>Simplifiez votre workflow de versioning avec des raccourcis puissants.</p><h2 id="apercu" tabindex="-1">Aperçu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Aperçu&quot;">​</a></h2><p>Les alias Git créent des raccourcis pour les commandes Git courantes. Faisant partie de la configuration <a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a>, ces alias se chargent automatiquement via Chezmoi.</p><p>Définis dans <code>git.aliases.sh</code> et <code>signing.aliases.sh</code>, ces alias sont disponibles dans toute session Bash ou Zsh une fois installés.</p><h2 id="reference" tabindex="-1">Référence <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Référence&quot;">​</a></h2><h3 id="noyau" tabindex="-1">Noyau <a class="header-anchor" href="#noyau" aria-label="Permalink to &quot;Noyau&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>g</code></td><td><code>git</code></td><td>Raccourci pour git</td></tr><tr><td><code>gtp</code></td><td><code>git rev-parse --show-toplevel</code></td><td>Afficher le répertoire racine du dépôt</td></tr><tr><td><code>grpa</code></td><td><code>git rev-parse --abbrev-ref HEAD</code></td><td>Afficher le nom de la branche courante</td></tr><tr><td><code>gconfl</code></td><td><code>git config --list</code></td><td>Lister toute la configuration Git</td></tr><tr><td><code>gconfr</code></td><td><code>git config --local --get remote.origin.url</code></td><td>Afficher l’URL du remote origin</td></tr><tr><td><code>gconfdiff</code></td><td><code>git config alias.dcolor &quot;diff --color-words&quot;</code></td><td>Configurer un alias diff en mots colorés</td></tr></tbody></table><h3 id="zone-de-travail" tabindex="-1">Zone de travail <a class="header-anchor" href="#zone-de-travail" aria-label="Permalink to &quot;Zone de travail&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>ga</code></td><td><code>git add</code></td><td>Stage des fichiers</td></tr><tr><td><code>gaa</code></td><td><code>git add --all</code></td><td>Stage tous les changements (suivis et non suivis)</td></tr><tr><td><code>gad</code></td><td><code>git add .</code></td><td>Stage tout dans le répertoire courant</td></tr><tr><td><code>gau</code></td><td><code>git add --update</code></td><td>Stage modifications et suppressions (sans nouveaux fichiers)</td></tr><tr><td><code>gcl</code></td><td><code>git clone</code></td><td>Cloner un dépôt</td></tr><tr><td><code>gin</code></td><td><code>git init</code></td><td>Initialiser un nouveau dépôt Git</td></tr><tr><td><code>gco</code></td><td><code>git checkout</code></td><td>Changer de branche ou restaurer des fichiers</td></tr><tr><td><code>gcb</code></td><td><code>git checkout -b</code></td><td>Créer et basculer sur une nouvelle branche</td></tr><tr><td><code>gdis</code></td><td><code>git checkout --</code></td><td>Annuler les changements du répertoire de travail</td></tr><tr><td><code>grs</code></td><td><code>git restore</code></td><td>Restaurer les fichiers du répertoire de travail</td></tr><tr><td><code>gmv</code></td><td><code>git mv</code></td><td>Déplacer ou renommer un fichier</td></tr><tr><td><code>grm</code></td><td><code>git rm</code></td><td>Supprimer des fichiers du dépôt et de l’index</td></tr><tr><td><code>grmc</code></td><td><code>git rm --cached</code></td><td>Désindexer un fichier (le conserver sur disque)</td></tr><tr><td><code>gst</code></td><td><code>git status</code></td><td>Afficher l’état du répertoire de travail</td></tr><tr><td><code>gsts</code></td><td><code>git status --short</code></td><td>État en format court</td></tr><tr><td><code>gstsb</code></td><td><code>git status --short --branch</code></td><td>État court avec branche et tracking</td></tr><tr><td><code>gsta</code></td><td><code>git stash save</code></td><td>Mettre de côté les changements</td></tr><tr><td><code>gstp</code></td><td><code>git stash pop</code></td><td>Appliquer et supprimer le dernier stash</td></tr><tr><td><code>gstd</code></td><td><code>git stash drop</code></td><td>Supprimer le dernier stash</td></tr><tr><td><code>gclout</code></td><td><code>git clean -df &amp;&amp; git checkout -- .</code></td><td>Annuler tous les changements et fichiers non suivis</td></tr></tbody></table><h3 id="commits" tabindex="-1">Commits <a class="header-anchor" href="#commits" aria-label="Permalink to &quot;Commits&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gc</code></td><td><code>git commit -a</code></td><td>Commit tous les fichiers suivis</td></tr><tr><td><code>gca</code></td><td><code>git commit --amend</code></td><td>Amender le dernier commit</td></tr><tr><td><code>gcall</code></td><td><code>git add -A &amp;&amp; git commit -av</code></td><td>Stager tout et commit en mode verbeux</td></tr><tr><td><code>gcam</code></td><td><code>git commit --amend --message</code></td><td>Amender avec un nouveau message</td></tr><tr><td><code>gcane</code></td><td><code>git commit --amend --no-edit</code></td><td>Amender sans changer le message</td></tr><tr><td><code>gcm</code></td><td><code>git commit --message</code></td><td>Commit avec message inline</td></tr></tbody></table><h3 id="diff-et-historique" tabindex="-1">Diff et historique <a class="header-anchor" href="#diff-et-historique" aria-label="Permalink to &quot;Diff et historique&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gd</code></td><td><code>git diff</code></td><td>Afficher les changements non stagés</td></tr><tr><td><code>gdch</code></td><td><code>git diff --name-status</code></td><td>Noms et statuts des fichiers modifiés</td></tr><tr><td><code>gdh</code></td><td><code>git diff HEAD</code></td><td>Tous les changements depuis le dernier commit</td></tr><tr><td><code>gdstaged</code></td><td><code>git diff --staged</code></td><td>Afficher les changements stagés</td></tr><tr><td><code>gdcached</code></td><td><code>git diff --cached</code></td><td>Diff entre index et HEAD</td></tr><tr><td><code>gdstat</code></td><td><code>git diff --stat --ignore-space-change -r</code></td><td>Diffstat en ignorant les espaces</td></tr><tr><td><code>gl</code></td><td><code>git log --since=&quot;last month&quot; --oneline</code></td><td>Log en une ligne du dernier mois</td></tr><tr><td><code>glg</code></td><td><code>git log --graph --all --oneline --decorate</code></td><td>Log graphique de toutes les branches</td></tr><tr><td><code>glgg</code></td><td><code>git log --oneline --graph --full-history --all --color --decorate</code></td><td>Log graphique complet avec couleurs</td></tr><tr><td><code>glc</code></td><td><code>git log --oneline --reverse</code></td><td>Log chronologique en une ligne</td></tr><tr><td><code>gld</code></td><td><code>git log --since=1-day-ago</code></td><td>Log des dernières 24 heures</td></tr><tr><td><code>gldc</code></td><td><code>git log -1 --date-order --format=%cI</code></td><td>Date ISO 8601 du dernier commit</td></tr><tr><td><code>gldl</code></td><td><code>git log --date=local</code></td><td>Log avec dates en timezone locale</td></tr><tr><td><code>glf</code></td><td><code>git log ORIG_HEAD.. --stat --no-merges</code></td><td>Nouveaux commits après fetch (sans merges)</td></tr><tr><td><code>gll</code></td><td><em>(format graphique décoré)</em></td><td>Log détaillé avec auteur et statut GPG</td></tr></tbody></table><h3 id="branches" tabindex="-1">Branches <a class="header-anchor" href="#branches" aria-label="Permalink to &quot;Branches&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gb</code></td><td><code>git branch</code></td><td>Lister les branches locales</td></tr><tr><td><code>gbd</code></td><td><code>git branch -d</code></td><td>Supprimer une branche fusionnée</td></tr><tr><td><code>gbl</code></td><td><code>git branch -l</code></td><td>Lister les branches par motif</td></tr><tr><td><code>gbr</code></td><td><code>git branch -r</code></td><td>Lister les branches distantes</td></tr><tr><td><code>gbrd</code></td><td><code>git branch -d -r</code></td><td>Supprimer une branche distante suivie</td></tr><tr><td><code>gbrsb</code></td><td><code>git show-branch</code></td><td>Afficher les branches et leurs commits</td></tr><tr><td><code>gswb</code></td><td><code>git switch</code></td><td>Changer de branche (moderne)</td></tr><tr><td><code>gcode</code></td><td><code>git checkout main &amp;&amp; git branch --merged | xargs git branch --delete</code></td><td>Supprimer les branches fusionnées dans main</td></tr><tr><td><code>gcom</code></td><td><code>git checkout main &amp;&amp; git fetch origin --prune &amp;&amp; git reset --hard origin/main</code></td><td>Réinitialiser main local sur origin/main</td></tr></tbody></table><h3 id="remotes-et-push-pull" tabindex="-1">Remotes et Push/Pull <a class="header-anchor" href="#remotes-et-push-pull" aria-label="Permalink to &quot;Remotes et Push/Pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gf</code></td><td><code>git fetch</code></td><td>Récupérer depuis le remote</td></tr><tr><td><code>gp</code></td><td><code>git pull</code></td><td>Tirer depuis le remote</td></tr><tr><td><code>gph</code></td><td><code>git push</code></td><td>Pousser vers le remote</td></tr><tr><td><code>gpo</code></td><td><code>git push origin</code></td><td>Pousser vers origin</td></tr><tr><td><code>gpb</code></td><td><code>git push --set-upstream origin $(git branch --show-current)</code></td><td>Pousser et définir l’upstream</td></tr><tr><td><code>gpoll</code></td><td><code>git push origin --all</code></td><td>Pousser toutes les branches vers origin</td></tr><tr><td><code>gpull</code></td><td><code>git pull</code></td><td>Tirer depuis le remote</td></tr><tr><td><code>gpush</code></td><td><code>git push</code></td><td>Pousser vers le remote</td></tr><tr><td><code>gr</code></td><td><code>git remote</code></td><td>Gérer les remotes</td></tr><tr><td><code>gra</code></td><td><code>git remote add</code></td><td>Ajouter un remote</td></tr><tr><td><code>grall</code></td><td><code>git remote | xargs -L1 git push --all</code></td><td>Pousser toutes les branches vers tous les remotes</td></tr><tr><td><code>grao</code></td><td><code>git remote add origin</code></td><td>Ajouter le remote origin</td></tr><tr><td><code>grv</code></td><td><code>git remote -v</code></td><td>Afficher les URL des remotes</td></tr></tbody></table><h3 id="revert-et-reset" tabindex="-1">Revert et Reset <a class="header-anchor" href="#revert-et-reset" aria-label="Permalink to &quot;Revert et Reset&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>grev</code></td><td><code>git revert</code></td><td>Revert un commit</td></tr><tr><td><code>grevnc</code></td><td><code>git revert --no-commit</code></td><td>Revert sans auto-commit</td></tr><tr><td><code>grb</code></td><td><code>git rebase</code></td><td>Rebaser la branche courante</td></tr><tr><td><code>grbk</code></td><td><code>git reset --soft HEAD^</code></td><td>Annuler le dernier commit, garder les changements stagés</td></tr><tr><td><code>grescl</code></td><td><code>git reset --hard HEAD~1 &amp;&amp; git clean -fd</code></td><td>Hard reset et nettoyage des fichiers non suivis</td></tr><tr><td><code>gresh</code></td><td><code>git reset --hard HEAD~1</code></td><td>Hard reset sur le commit précédent</td></tr><tr><td><code>gresp</code></td><td><code>git reset --hard &amp;&amp; git clean -ffdx</code></td><td>Réinitialiser tout à l’état initial</td></tr><tr><td><code>gress</code></td><td><code>git reset --soft HEAD~1</code></td><td>Soft reset (garder les changements stagés)</td></tr></tbody></table><h3 id="sous-modules" tabindex="-1">Sous-modules <a class="header-anchor" href="#sous-modules" aria-label="Permalink to &quot;Sous-modules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gsm</code></td><td><code>git submodule</code></td><td>Gérer les sous-modules</td></tr><tr><td><code>gsmi</code></td><td><code>git submodule init</code></td><td>Initialiser les sous-modules</td></tr><tr><td><code>gsma</code></td><td><code>git submodule add</code></td><td>Ajouter un sous-module</td></tr><tr><td><code>gsms</code></td><td><code>git submodule sync</code></td><td>Synchroniser les URLs avec .gitmodules</td></tr><tr><td><code>gsmu</code></td><td><code>git submodule update</code></td><td>Mettre à jour les sous-modules</td></tr><tr><td><code>gsmui</code></td><td><code>git submodule update --init</code></td><td>Mettre à jour et initialiser</td></tr><tr><td><code>gsmuir</code></td><td><code>git submodule update --init --recursive</code></td><td>Mettre à jour, initialiser et récursiver</td></tr></tbody></table><h3 id="outils" tabindex="-1">Outils <a class="header-anchor" href="#outils" aria-label="Permalink to &quot;Outils&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>gg</code></td><td><code>git grep</code></td><td>Rechercher dans le dépôt</td></tr><tr><td><code>gbs</code></td><td><code>git bisect</code></td><td>Recherche binaire d’un commit fautif</td></tr><tr><td><code>undopush</code></td><td><code>git push -f origin HEAD^:master</code></td><td>Annuler le dernier push vers master</td></tr></tbody></table><h3 id="signature-et-securite" tabindex="-1">Signature et sécurité <a class="header-anchor" href="#signature-et-securite" aria-label="Permalink to &quot;Signature et sécurité&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Commande</th><th>Description</th></tr></thead><tbody><tr><td><code>enable-signing</code></td><td><em>(assistant interactif)</em></td><td>Configurer la signature GPG ou SSH des commits</td></tr><tr><td><code>verify-signatures</code></td><td><code>git log --show-signature -n 10</code></td><td>Vérifier les signatures des 10 derniers commits</td></tr><tr><td><code>check-signing</code></td><td><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td>Vérifier la configuration de signature actuelle</td></tr></tbody></table>',26)])])}const m=e(c,[["render",i]]);export{h as __pageData,m as default};
